CREATE TABLE IF NOT EXISTS parsed_urls (id SERIAL PRIMARY KEY, url TEXT NOT NULL, title TEXT, description TEXT, status TEXT DEFAULT 'pending', parsed_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP); CREATE TABLE IF NOT EXISTS tasks (id SERIAL PRIMARY KEY, title TEXT NOT NULL, description TEXT, status TEXT DEFAULT 'pending', created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP); CREATE INDEX IF NOT EXISTS idx_parsed_urls_url ON parsed_urls(url); CREATE INDEX IF NOT EXISTS idx_tasks_status ON tasks(status);
